document.addEventListener("DOMContentLoaded",()=>{typeof panzoom=="undefined"?window.panzoom?initPanzoom():console.warn("panzoom library not loaded"):initPanzoom()});function initPanzoom(){document.querySelectorAll(".d2-container").forEach(e=>{const n=e.querySelector(".d2-wrapper");if(!n)return;const s=n.querySelector("img");if(!s)return;const t=panzoom(s,{maxZoom:5,minZoom:.1,initialZoom:1,bounds:!1,boundsPadding:.1}),o=()=>{const e=n.getBoundingClientRect();return{x:e.left+e.width/2,y:e.top+e.height/2}},i=e.querySelector(".d2-btn-zoom-in"),a=e.querySelector(".d2-btn-zoom-out"),r=e.querySelector(".d2-btn-reset");i&&i.addEventListener("click",e=>{e.preventDefault(),e.stopPropagation();const n=o();t.smoothZoom(n.x,n.y,1.25)}),a&&a.addEventListener("click",e=>{e.preventDefault(),e.stopPropagation();const n=o();t.smoothZoom(n.x,n.y,.8)}),r&&r.addEventListener("click",e=>{e.preventDefault(),e.stopPropagation(),t.moveTo(0,0),t.zoomAbs(0,0,1)})})}